import flask
from flask import request, jsonify
import os
import json
from collections import Counter

app = flask.Flask(__name__)
app.config["DEBUG"] = True

# Mock database to store labels
label_db = {}

@app.route('/upload_label', methods=['POST'])
def upload_label():
    data = request.get_json()
    image_id = data['image_id']
    label = data['label']

    # Validate input
    if not isinstance(image_id, str) or not isinstance(label, str):
        return jsonify({"error": "Invalid input"}), 400

    if image_id not in label_db:
        label_db[image_id] = []

    label_db[image_id].append(label)

    return jsonify({"message": "Label uploaded successfully"}), 200

@app.route('/get_labels', methods=['GET'])
def get_labels():
    image_id = request.args.get('image_id')

    if not isinstance(image_id, str):
        return jsonify({"error": "Invalid input"}), 400

    if image_id in label_db:
        labels = label_db[image_id]
        majority_label = Counter(labels).most_common(1)[0][0]
        return jsonify({"majority_label": majority_label}), 200
    else:
        return jsonify({"message": "No labels available for this image"}), 404

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)